import React, { useState } from "react";
import { Link } from "react-router-dom";
import "./Profile.css";

export default function Profile() {
  const [name, setName] = useState(localStorage.getItem("userName") || "");
  const roll = localStorage.getItem("rollNumber") || "";
  const [email, setEmail] = useState(localStorage.getItem("email") || "");
  const [contact, setContact] = useState(localStorage.getItem("contact") || "");
  const [year, setYear] = useState(localStorage.getItem("year") || "");
  const [semester, setSemester] = useState(localStorage.getItem("semester") || "");
  const [photo, setPhoto] = useState(localStorage.getItem("profilePhoto") || "");

  const handleSave = () => {
    localStorage.setItem("userName", name);
    localStorage.setItem("email", email);
    localStorage.setItem("contact", contact);
    localStorage.setItem("year", year);
    localStorage.setItem("semester", semester);
    localStorage.setItem("profilePhoto", photo);
    alert("Profile updated successfully!");
  };

  const handlePhotoChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setPhoto(reader.result);
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="profile-card">
      <h2>Student Profile</h2>
      <div className="profile-photo">
        <img src={photo || "https://via.placeholder.com/150"} alt="Profile" />
        <input type="file" accept="image/*" onChange={handlePhotoChange} />
      </div>
      <div className="profile-info">
        <label>Roll No:</label>
        <p className="readonly">{roll}</p>

        <label>Name:</label>
        <input value={name} onChange={(e) => setName(e.target.value)} />

        <label>Email:</label>
        <input value={email} onChange={(e) => setEmail(e.target.value)} />

        <label>Contact:</label>
        <input value={contact} onChange={(e) => setContact(e.target.value)} />

        <label>Year:</label>
        <input value={year} onChange={(e) => setYear(e.target.value)} />

        <label>Semester:</label>
        <input value={semester} onChange={(e) => setSemester(e.target.value)} />
      </div>

      <button onClick={handleSave} className="save-btn">Save Changes</button>
      <Link to="/dashboard" className="back-link">← Back to Dashboard</Link>
    </div>
  );
}
